#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long *B = (long long*)malloc(N*sizeof(long long));
        long long sumB = 0;
        for(int i=0;i<N;i++){
            scanf("%lld", &B[i]);
            sumB += B[i];
        }
        long long total = sumB / (N + 1LL);
        for(int i=0;i<N;i++){
            long long Ai = B[i] - total;
            printf("%lld", Ai);
            if(i+1<N) printf(" ");
        }
        printf("\n");
        free(B);
    }
    return 0;
}

